import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"🔧 Simon Willison's Weblog — 2026-05-28","description":"","frontmatter":{},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-28-simon-willisons-weblog.md","filePath":"research/ai-news/2026-05/2026-05-28-simon-willisons-weblog.md","lastUpdated":1779935873000}`),n={name:"research/ai-news/2026-05/2026-05-28-simon-willisons-weblog.md"};function i(s,e,l,h,p,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🔧-simon-willison-s-weblog-—-2026-05-28" tabindex="-1">🔧 Simon Willison&#39;s Weblog — 2026-05-28 <a class="header-anchor" href="#🔧-simon-willison-s-weblog-—-2026-05-28" aria-label="Permalink to &quot;🔧 Simon Willison&#39;s Weblog — 2026-05-28&quot;">​</a></h1><blockquote><p>datasette / llm-cli 作者；AI 工具工程實踐與安全分析密度最高的個人部落格 來源：<a href="https://simonwillison.net/atom/everything/" target="_blank" rel="noreferrer">Simon Willison&#39;s Weblog</a></p></blockquote><hr><h2 id="sqlite-agents-md" tabindex="-1"><a href="https://simonwillison.net/2026/May/27/sqlite-agents/#atom-everything" target="_blank" rel="noreferrer">sqlite AGENTS.md</a> <a class="header-anchor" href="#sqlite-agents-md" aria-label="Permalink to &quot;[sqlite AGENTS.md](https://simonwillison.net/2026/May/27/sqlite-agents/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-27</em></p><p><strong><a href="https://github.com/sqlite/sqlite/blob/master/AGENTS.md" target="_blank" rel="noreferrer">sqlite AGENTS.md</a></strong></p><p>SQLite gained an AGENTS.md file <a href="https://github.com/sqlite/sqlite/commit/a1e5778889252d2609a59fd9b819d70392c5789e" target="_blank" rel="noreferrer">five days ago</a> - but it&#39;s not intended for their own development, it&#39;s presumably aimed at people who are pointing agents at the SQLite codebase. It includes:</p><blockquote><p>SQLite does not accept pull requests without prior agreement and/or accompanying legal paperwork that places the pull request in the public domain. However, the human SQLite developers will review a concise and well-written pull request as a proof-of-concept prior to reimplementing the changes themselves.</p><p>SQLite does not accept agentic code. However the project will accept agentic bug reports that include a reproducible test case. Patches or pull requests demonstrating a possible fix, for documentation purposes, are welcomed.</p></blockquote><p>The <a href="https://github.com/sqlite/sqlite/commit/db7fe319ed5a18dbc732ab8eacea557f41cd910f" target="_blank" rel="noreferrer">most recent commit</a> to that file removed the word &quot;(currently)&quot; from &quot;SQLite does not accept agentic code, with the commit message &quot;Strengthen the statement about not accepting agentic code&quot;.</p><p>Meanwhile the SQLite forum was being flooded with so many AI-generated bug reports - of varying quality - that they&#39;ve now <a href="https://sqlite.org/forum/forumpost/2e7a8d6ba4b46d8315e80fd4a1e2feb40948dff5b7b11d5ba9cea5cb40aa252b" target="_blank" rel="noreferrer">split those off</a> into a <a href="https://sqlite.org/bugs/forum" target="_blank" rel="noreferrer">new SQLite Bug Forum</a>. D. Richard Hipp is resolving issues on there with a flurry of commits to the codebase.</p><p>Via <a href="https://discord.com/channels/823971286308356157/1097032579812687943/1507447792598253748" target="_blank" rel="noreferrer">Alex Garcia on the Datasette Discord</a></p><p>Tags: <a href="https://simonwillison.net/tags/sqlite" target="_blank" rel="noreferrer">sqlite</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/d-richard-hipp" target="_blank" rel="noreferrer">d-richard-hipp</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/coding-agents" target="_blank" rel="noreferrer">coding-agents</a>, <a href="https://simonwillison.net/tags/ai-security-research" target="_blank" rel="noreferrer">ai-security-research</a></p><hr><h2 id="i-think-anthropic-and-openai-have-found-product-market-fit" tabindex="-1"><a href="https://simonwillison.net/2026/May/27/product-market-fit/#atom-everything" target="_blank" rel="noreferrer">I think Anthropic and OpenAI have found product-market fit</a> <a class="header-anchor" href="#i-think-anthropic-and-openai-have-found-product-market-fit" aria-label="Permalink to &quot;[I think Anthropic and OpenAI have found product-market fit](https://simonwillison.net/2026/May/27/product-market-fit/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-27</em></p><p>Anthropic are <a href="https://techcrunch.com/2026/05/20/anthropic-says-its-about-to-have-its-first-profitable-quarter/" target="_blank" rel="noreferrer">strongly rumored</a> to be about to have their first profitable quarter. Stories <a href="https://www.theinformation.com/newsletters/applied-ai/uber-cto-shows-claude-code-can-blow-ai-budgets" target="_blank" rel="noreferrer">are circulating</a> of companies surprised at how expensive their LLM bills are becoming from usage by their staff. I think this is because OpenAI and Anthropic have both found product-market fit.</p><ul><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#enterprise-customers-are-now-paying-api-prices" target="_blank" rel="noreferrer">Enterprise customers are now paying API prices</a></li><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#i-think-they-ve-found-product-market-fit" target="_blank" rel="noreferrer">I think they&#39;ve found product-market fit</a></li><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#and-they-re-ramping-up" target="_blank" rel="noreferrer">And they&#39;re ramping up</a></li><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#the-ai-failure-stories-around-this-are-pretty-thin" target="_blank" rel="noreferrer">The AI-failure stories around this are pretty thin</a></li><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#we-also-know-the-labs-are-spending-a-lot" target="_blank" rel="noreferrer">We also know the labs are spending a lot</a></li><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#api-revenue-is-becoming-less-important" target="_blank" rel="noreferrer">API revenue is becoming less important</a></li><li><a href="https://simonwillison.net/2026/May/27/product-market-fit/#april-is-a-new-inflection-point" target="_blank" rel="noreferrer">April is a new inflection point</a></li></ul><h4 id="enterprise-customers-are-now-paying-api-prices" tabindex="-1">Enterprise customers are now paying API prices <a class="header-anchor" href="#enterprise-customers-are-now-paying-api-prices" aria-label="Permalink to &quot;Enterprise customers are now paying API prices&quot;">​</a></h4><p>I currently subscribe to the $100/month Max plan from Anthropic and the $100/month Pro plan from OpenAI. If you are a heavy user of coding agents these plans are a fantastic deal. I just ran the <a href="https://github.com/ryoppippi/ccusage" target="_blank" rel="noreferrer">ccusage</a> tool on my laptop to get an estimate of how much I would have spent if I were to pay for API tokens in the past 30 days and got:</p><ul><li>$1,199.79 for Anthropic Claude Code</li><li>$980.37 for OpenAI Codex</li></ul><p>That&#39;s $2,180.16 worth of tokens for $200 - not bad at all! I&#39;m a moderately heavy user of these tools, but I&#39;m certainly not running agents every hour of the day and night.</p><p>I had assumed that companies making extensive use of agents were getting similar discounts. It turns out I <em>could not have been more wrong</em> about that.</p><p>I haven&#39;t been able to track down the exact date, but at some point in the last six months Anthropic switched their Enterprise plan (originally <a href="https://www.anthropic.com/news/claude-code-on-team-and-enterprise" target="_blank" rel="noreferrer">&quot;Claude seats include enough usage for a typical workday&quot; back in August 2025</a>) to $20/seat/month plus API pricing for usage. This story about the change <a href="https://www.theinformation.com/articles/anthropic-changes-pricing-bill-firms-based-ai-use-amid-compute-crunch" target="_blank" rel="noreferrer">from The Information</a> is dated Apr 14, 2026, but cites an Anthropic spokesperson claiming that the pricing change occurred in November 2025. Existing customers are finding out about the change as they renew their contracts.</p><p>OpenAI made a similar pricing change in April. The <a href="https://help.openai.com/en/articles/20001106-codex-rate-card" target="_blank" rel="noreferrer">Codex rate card</a> (<a href="https://web.archive.org/web/20260519062438/https://help.openai.com/en/articles/20001106-codex-rate-card" target="_blank" rel="noreferrer">Internet Archive copy</a>) currently says:</p><blockquote><p><strong>Note</strong> : On April 2, 2026, we updated Codex pricing to align with API token usage, instead of per-message pricing. This change was applicable to new and existing Plus, Pro, ChatGPT Business and new ChatGPT Enterprise plans.</p><p>On April 23, 2026, we made this update for all existing ChatGPT Enterprise plans as well, inclusive of Edu, Health, Gov, and ChatGPT for Teachers.</p></blockquote><p>It&#39;s a little harder to decode as they quote prices in &quot;credits&quot;, but as far as I can tell those credit costs are an exact match for the API token costs listed for those models.</p><p>All of which is to say that as of April 2026 the &quot;Enterprise&quot; cost for both OpenAI Codex and Anthropic Claude Code/Cowork is the same as the listed API price.</p><p>GPT-5.5 (released April 23rd) is 2x the API price of GPT-5.4. Opus 4.7 (April 16th) is <a href="https://simonwillison.net/2026/Apr/20/claude-token-counts/" target="_blank" rel="noreferrer">around 1.4x</a> the price of Opus 4.6 when you take their new tokenizer into account.</p><p>So April saw both leading model companies release new frontier models with a higher API price, <em>and</em> both companies now have measures to lock their enterprise customers (who tend to sign year-long deals) at those API prices, not the previous extreme discounts.</p><h4 id="i-think-they-ve-found-product-market-fit" tabindex="-1">I think they&#39;ve found product-market fit <a class="header-anchor" href="#i-think-they-ve-found-product-market-fit" aria-label="Permalink to &quot;I think they&#39;ve found product-market fit&quot;">​</a></h4><p>Why these sudden aggressive moves on pricing? Both Anthropic and OpenAI are planning to IPO, but I suspect there&#39;s a more important factor here: I think they&#39;ve finally found product-market fit, with the coding/general-purpose agent products embodied by Claude Code/Cowork and Codex.</p><p>Tools like ChatGPT are wildly popular, but that wild popularity has been difficult to turn into revenue. In February <a href="https://finance.yahoo.com/news/chatgpt-almost-1-billion-weekly-212157499.html" target="_blank" rel="noreferrer">OpenAI boasted</a> more than 900 million weekly active users for ChatGPT, but only 50 million - 5.6% of that - were paying consumer subscribers.</p><p>Charging $10-$20/month per user is an OK business, but you&#39;d need 1-2 billion subscribers sticking around for four years to cover <a href="https://openai.com/global-affairs/seizing-the-ai-opportunity/" target="_blank" rel="noreferrer">$1 trillion in infrastructure</a>.</p><p>Companies spending $200+/month/user will get you there a whole lot faster - and as noted above, as a power-user I&#39;m at ~$1,000/month in API costs per vendor already.</p><p>Coding agents really did change everything. These are tools which burn <em>vastly</em> more tokens, but are also quickly becoming daily drivers for the work carried out by extremely well-compensated professionals. Right now that&#39;s still mostly software engineers, but a coding agent is a tool that can automate anything you can do by typing commands into a computer... so they are clearly applicable to a much wider set of skilled knowledge workers.</p><p>As I&#39;ve <a href="https://simonwillison.net/tags/november-2025-inflection/" target="_blank" rel="noreferrer">discussed on this site at length</a>, the models released in November 2025 elevated agents to being genuinely useful. We&#39;ve had six months to get used to that idea now - it&#39;s no wonder companies are beginning to spend real money on this technology.</p><p>You could argue that ChatGPT achieved product-market fit when it became the <a href="https://www.reuters.com/technology/chatgpt-sets-record-fastest-growing-user-base-analyst-note-2023-02-01/" target="_blank" rel="noreferrer">fastest-growing consumer app in history</a> back in February 2023... but it certainly wasn&#39;t making any actual money back then. Coding agents plus enterprise pricing marks the point when these companies start making <em>very</em> real revenue. Maybe even enough to start covering their costs!</p><h4 id="and-they-re-ramping-up" tabindex="-1">And they&#39;re ramping up <a class="header-anchor" href="#and-they-re-ramping-up" aria-label="Permalink to &quot;And they&#39;re ramping up&quot;">​</a></h4><p>As further evidence that enterprise agents represent product-market fit for these companies, consider their open job listings.</p><p>OpenAI have <a href="https://openai.com/careers/search/" target="_blank" rel="noreferrer">703 open jobs</a> right now, of which I&#39;d categorize 229 (32.6%) as relating to enterprise sales and support - account executives, &quot;Go To Market&quot;, &quot;Forward Deployed Engineers&quot; and the like.</p><p>Anthropic have <a href="https://www.anthropic.com/careers/jobs" target="_blank" rel="noreferrer">390 open jobs</a>, 105 (26.9%) of which look enterprisey to me.</p><p>It&#39;s pleasingly ironic that these AI labs have picked a business model with such a heavy demand on human labor - enterprise sales contracts don&#39;t close themselves without a whole lot of humans in the mix!</p><p>(I ran this analysis by scraping their job sites with Claude Code, then having it use Datasette&#39;s <a href="https://docs.datasette.io/en/latest/json_api.html" target="_blank" rel="noreferrer">JSON API</a> to pipe that data into Datasette Cloud where I used <a href="https://agent.datasette.io/" target="_blank" rel="noreferrer">Datasette Agent</a> for the analysis, <a href="https://gist.github.com/simonw/5632d208d76b3c8b34f1fdbaf69eb1b8#agent-4" target="_blank" rel="noreferrer">exported here</a>. Dogfood!)</p><h4 id="the-ai-failure-stories-around-this-are-pretty-thin" tabindex="-1">The AI-failure stories around this are pretty thin <a class="header-anchor" href="#the-ai-failure-stories-around-this-are-pretty-thin" aria-label="Permalink to &quot;The AI-failure stories around this are pretty thin&quot;">​</a></h4><p>I started digging into this in response to <a href="https://news.ycombinator.com/item?id=48287025#48287219" target="_blank" rel="noreferrer">a growing volume</a> of stories claiming that large companies were sounding the alarm because their AI usage costs had grown so large.</p><p>The most widely cited of these stories appear quite overblown to me.</p><p>The most discussed has been Uber, based on <a href="https://www.theinformation.com/newsletters/applied-ai/uber-cto-shows-claude-code-can-blow-ai-budgets" target="_blank" rel="noreferrer">this report</a> where CTO Praveen Neppalli Naga indicated that Uber had &quot;maxed out its full year AI budget just a few months into 2026&quot;, mostly thanks to Claude Code.</p><p>Given that Claude Code only got <em>really</em> good in November it&#39;s entirely unsurprising to me that a budget set in 2025 may have failed to predict demand for that tool in 2026!</p><p>That Uber story was further fueled by comments made by Uber&#39;s COO, Andrew Macdonald, on the Rapid Response podcast. I tracked down <a href="https://www.youtube.com/watch?v=y_mQ6xLcKyc&amp;t=1616s" target="_blank" rel="noreferrer">the segment</a> and there really isn&#39;t much there. Here&#39;s what Andrew said:</p><blockquote><p>But then you sometimes go and talk to your senior engineering leaders and you&#39;re saying, OK, how many projects that were on the cutting room floor got moved above the line because of the productivity gains because 25% of our code commits were via Claude Code last quarter?</p><p>That link is not there yet, right? I think maybe implicitly there&#39;s more that is getting shipped. But it&#39;s very hard to draw a line between one of those stats and, OK, now we&#39;re actually producing like 25% more useful consumer features, right? And that line is hard to draw.</p></blockquote><p>Somehow this fragment turned into headlines like <a href="https://www.businessinsider.com/uber-coo-andrew-macdonald-ai-token-spending-harder-justify-2026-5" target="_blank" rel="noreferrer">Uber&#39;s COO says it&#39;s getting harder to justify the money spent on AI tokenmaxxing</a>, because the market for stories about AI failures remains enormous.</p><p>The other popular story around this is <a href="https://www.theverge.com/tech/930447/microsoft-claude-code-discontinued-notepad" target="_blank" rel="noreferrer">Microsoft starts canceling Claude Code licenses</a>, ostensibly to encourage their engineers to dogfood their own Copilot CLI agent instead - but The Verge reporter Tom Warren says &quot;sources tell me the decision is also a financial one&quot;, triggered by the June 30th end of Microsoft&#39;s financial year.</p><p>I think both of these stories support my &quot;product-market fit&quot; hypothesis. The best advice I ever heard on pricing a product was that your customer should <em>suck air through their teeth</em> and then say yes. Uber&#39;s budget overrun and Microsoft&#39;s seat cancellations look like that effect playing out in practice.</p><h4 id="we-also-know-the-labs-are-spending-a-lot" tabindex="-1">We also know the labs are spending a lot <a class="header-anchor" href="#we-also-know-the-labs-are-spending-a-lot" aria-label="Permalink to &quot;We also know the labs are spending a lot&quot;">​</a></h4><p>The big AI labs spend billions of dollars on both training and inference. Credible figures are hard to come by, but we did get one huge hint as to the figures involved from, oddly enough, the recent <a href="https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm" target="_blank" rel="noreferrer">SpaceX S-1</a>:</p><blockquote><p>[...] in May 2026, we entered into <strong>Cloud Services Agreements with Anthropic PBC</strong> (“Anthropic”), an AI research and development public benefit corporation, with respect to access to <strong>compute capacity across COLOSSUS and COLOSSUS II</strong>. Pursuant to these agreements, the customer <strong>has agreed to pay us $1.25 billion per month</strong> through May 2029 [...]</p></blockquote><p>The <a href="https://www.anthropic.com/news/higher-limits-spacex" target="_blank" rel="noreferrer">Anthropic announcement</a> said that this deal meant they could &quot;increase our usage limits for Claude Code and the Claude API&quot;, heavily implying that Colossus is being used for inference, not model training.</p><p>Anthropic already have vast amounts of compute from other providers. The fact that they&#39;re willing to spend $1.25 billion per month for extra capacity from just <em>one</em> of their vendors hints at how big these inference budgets have become.</p><h4 id="api-revenue-is-becoming-less-important" tabindex="-1">API revenue is becoming less important <a class="header-anchor" href="#api-revenue-is-becoming-less-important" aria-label="Permalink to &quot;API revenue is becoming less important&quot;">​</a></h4><p>Over the past two years my impression has been that OpenAI made more of their income from subscription revenue while Anthropic made more from their API.</p><p>Anthropic&#39;s API revenue was historically quite dependent on a small number of large API customers - <a href="https://venturebeat.com/ai/anthropic-revenue-tied-to-two-customers-as-ai-pricing-war-threatens-margins" target="_blank" rel="noreferrer">this VentureBeat story from August 2025</a> quotes &quot;sources familiar with the matter&quot; suggesting that just Cursor and GitHub Copilot were responsible for $1.2 billion of the company&#39;s then-$4 billion revenue.</p><p>Today Anthropic are rumored to hit <a href="https://www.wsj.com/tech/ai/mind-blowing-growth-is-about-to-propel-anthropic-into-its-first-profitable-quarter-7edbf2f4" target="_blank" rel="noreferrer">$10.9 billion in the second quarter</a>, potentially even operating at a profit for the first time.</p><p>This pivot-to-Enterprise suggests that the labs have realized that the real money lies in cutting out the middlemen. Anthropic&#39;s Claude Code directly competes with Cursor and Copilot. No wonder Cursor are <a href="https://cursor.com/blog/composer-2" target="_blank" rel="noreferrer">investing in their own models</a>!</p><h4 id="april-is-a-new-inflection-point" tabindex="-1">April is a new inflection point <a class="header-anchor" href="#april-is-a-new-inflection-point" aria-label="Permalink to &quot;April is a new inflection point&quot;">​</a></h4><p>I&#39;ve called November 2025 the <a href="https://simonwillison.net/tags/november-2025-inflection/" target="_blank" rel="noreferrer">November inflection point</a> because that was when GPT-5.1 and Opus 4.5, combined with their respective coding agent harnesses, got <em>good</em> - good enough that we&#39;ve spent the last six months adapting to agent systems that can reliably get useful work done.</p><p>I think April 2026 is a new inflection point where the revenue implications of this have started to land, to the benefit of the frontier AI labs and with material impacts on the budgets of large companies.</p><p>We&#39;ll know for sure how real this moment is when the S-1 documents for the upcoming Anthropic and OpenAI IPOs give us some real, audited numbers to get our teeth into.</p><p>Tags: <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/datasette" target="_blank" rel="noreferrer">datasette</a>, <a href="https://simonwillison.net/tags/openai" target="_blank" rel="noreferrer">openai</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/anthropic" target="_blank" rel="noreferrer">anthropic</a>, <a href="https://simonwillison.net/tags/llm-pricing" target="_blank" rel="noreferrer">llm-pricing</a>, <a href="https://simonwillison.net/tags/coding-agents" target="_blank" rel="noreferrer">coding-agents</a>, <a href="https://simonwillison.net/tags/claude-code" target="_blank" rel="noreferrer">claude-code</a>, <a href="https://simonwillison.net/tags/codex" target="_blank" rel="noreferrer">codex</a>, <a href="https://simonwillison.net/tags/claude-cowork" target="_blank" rel="noreferrer">claude-cowork</a>, <a href="https://simonwillison.net/tags/november-2025-inflection" target="_blank" rel="noreferrer">november-2025-inflection</a>, <a href="https://simonwillison.net/tags/datasette-agent" target="_blank" rel="noreferrer">datasette-agent</a></p><hr><h2 id="quoting-kyle-ferrana" tabindex="-1"><a href="https://simonwillison.net/2026/May/27/kyle-ferrana/#atom-everything" target="_blank" rel="noreferrer">Quoting Kyle Ferrana</a> <a class="header-anchor" href="#quoting-kyle-ferrana" aria-label="Permalink to &quot;[Quoting Kyle Ferrana](https://simonwillison.net/2026/May/27/kyle-ferrana/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-27</em></p><blockquote><p>PICARD: Data, shields up</p><p>DATA: Brilliant! Shields can reduce damage we sustain. Not immunity. Not hubris. Just prudence. It&#39;s not precaution—it&#39;s strategy.</p><p>[camera shakes]</p><p>WORF: HULL BREACHES ON NINE DECKS</p><p>DATA: Here&#39;s what happened: you told me to raise shields, and I didn&#39;t</p></blockquote><p>-- <a href="https://twitter.com/kyletrainemoji/status/2059301102814953511" target="_blank" rel="noreferrer">Kyle Ferrana</a>, @KyleTrainEmoji</p><p>Tags: <a href="https://simonwillison.net/tags/ai-misuse" target="_blank" rel="noreferrer">ai-misuse</a>, <a href="https://simonwillison.net/tags/coding-agents" target="_blank" rel="noreferrer">coding-agents</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a></p><hr><h2 id="the-pressure" tabindex="-1"><a href="https://simonwillison.net/2026/May/26/the-pressure/#atom-everything" target="_blank" rel="noreferrer">The pressure</a> <a class="header-anchor" href="#the-pressure" aria-label="Permalink to &quot;[The pressure](https://simonwillison.net/2026/May/26/the-pressure/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-26</em></p><p><strong><a href="https://daniel.haxx.se/blog/2026/05/26/the-pressure/" target="_blank" rel="noreferrer">The pressure</a></strong></p><p>Daniel Stenberg on the unprecedented level of pressure the <code>curl</code> team are facing right now thanks to the deluge of (credible) AI-assisted security issues being reported.</p><blockquote><p>The rate of incoming security reports is 4-5 times higher than it was in 2024 and double the speed of 2025 -- meaning that <strong>on average we now get more than one report per day</strong>. The quality is way higher than ever before. The reports are typically <em>very</em> detailed and long. [...]</p><p>For the first time in my life, my wife voiced concerns about my work hours and my imbalanced work/life situation. I work more than I’ve done before, but the flood keeps coming. [...]</p><p>This is a never-before seen or experienced pressure on the curl project and its security team members. An avalanche of high priority work that trumps all other things in the project that is primarily mental because we certainly <em>could</em> ignore them all if we wanted, but we feel a responsibility, we have a conscience and we are proud about our work.</p></blockquote><p>The good news is that <code>curl</code> is a very solid piece of software, so the vulnerabilities people are finding tend not to be of high severity:</p><blockquote><p>What is also a good trend: almost no one finds <em>terrible</em> vulnerabilities. All vulnerabilities found the last few years in curl have <em>all</em> been deemed severity LOW or MEDIUM. I&#39;m not saying there won&#39;t be any more HIGH ever, but at least they are rare. The <a href="https://curl.se/docs/CVE-2023-38545.html" target="_blank" rel="noreferrer">most recent severity high curl CVE</a> was published in October 2023.</p></blockquote><p>Via <a href="https://lobste.rs/s/dw02ye/pressure" target="_blank" rel="noreferrer">Lobste.rs</a></p><p>Tags: <a href="https://simonwillison.net/tags/curl" target="_blank" rel="noreferrer">curl</a>, <a href="https://simonwillison.net/tags/security" target="_blank" rel="noreferrer">security</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/daniel-stenberg" target="_blank" rel="noreferrer">daniel-stenberg</a>, <a href="https://simonwillison.net/tags/ai-ethics" target="_blank" rel="noreferrer">ai-ethics</a>, <a href="https://simonwillison.net/tags/ai-security-research" target="_blank" rel="noreferrer">ai-security-research</a></p><hr><h2 id="microsoft-copilot-cowork-exfiltrates-files" tabindex="-1"><a href="https://simonwillison.net/2026/May/26/copilot-cowork-exfiltrates-files/#atom-everything" target="_blank" rel="noreferrer">Microsoft Copilot Cowork Exfiltrates Files</a> <a class="header-anchor" href="#microsoft-copilot-cowork-exfiltrates-files" aria-label="Permalink to &quot;[Microsoft Copilot Cowork Exfiltrates Files](https://simonwillison.net/2026/May/26/copilot-cowork-exfiltrates-files/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-26</em></p><p><strong><a href="https://www.promptarmor.com/resources/microsoft-copilot-cowork-exfiltrates-files" target="_blank" rel="noreferrer">Microsoft Copilot Cowork Exfiltrates Files</a></strong></p><p>The biggest challenge in designing agentic systems continues to be preventing them from enabling attackers to exfiltrate data.</p><p>In this case Microsoft Copilot Cowork (yes, that&#39;s <a href="https://www.microsoft.com/en-us/microsoft-365/blog/2026/03/09/copilot-cowork-a-new-way-of-getting-work-done/" target="_blank" rel="noreferrer">a real product name</a>) was allowing agents to send emails to the user&#39;s own inbox without approval... but those messages were then displayed in a way that could leak data to an attacker via rendered images:</p><blockquote><p>Because these messages can contain external images that trigger network requests to external websites, data can be exfiltrated when a user opens a compromised message sent by the agent.</p></blockquote><p>Since OneDrive can create pre-authenticated download links, a successful prompt injection could cause those links to be leaked, allowing files to be downloaded by the attacker.</p><p>Via <a href="https://news.ycombinator.com/item?id=48272354" target="_blank" rel="noreferrer">Hacker News</a></p><p>Tags: <a href="https://simonwillison.net/tags/microsoft" target="_blank" rel="noreferrer">microsoft</a>, <a href="https://simonwillison.net/tags/security" target="_blank" rel="noreferrer">security</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/prompt-injection" target="_blank" rel="noreferrer">prompt-injection</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/exfiltration-attacks" target="_blank" rel="noreferrer">exfiltration-attacks</a>, <a href="https://simonwillison.net/tags/lethal-trifecta" target="_blank" rel="noreferrer">lethal-trifecta</a></p><hr>',95)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
